function objs(r){const a=[];if(r&&typeof r==='object')a.push(r);['raw','original','source','sourceRow','row','data'].forEach(k=>{const x=r?.[k];if(x&&typeof x==='object'&&!Array.isArray(x))a.push(x)});return a}
