function pkey(r){return[r.brand,r.size,r.code||r.sku,r.sku,r.type].join('|')}function group(rs){const m=new Map();rs.forEach(r=>{const k=pkey(r);let g=m.get(k);if(!g){g={poolKey:k,brand:r.brand,size:r.size,code:r.code,sku:r.sku,type:r.type,qty:0,amt:0,unit:r.unit||0,bills:new Set(),stores:new Map(),rows:[],inserted:false};m.set(k,g)}g.qty+=r.qty;g.amt+=r.amt;g.unit=g.qty&&g.amt?g.amt/g.qty:g.unit;g.bills.add(r.inv);g.stores.set(r.store,(g.stores.get(r.store)||0)+r.qty);g.rows.push(r)});return[...m.values()].sort((a,b)=>a.brand.localeCompare(b.brand,'th')||a.size.localeCompare(b.size,'th')||a.sku.localeCompare(b.sku,'th'))}
