function scope(){return[sel.dates.join(','),sel.ps.join(','),sel.orderStores.join(',')].join('|')+'|'}function rkey(pk,store=rec()){return[scope(),store,pk].join('|')}function pkKey(k){return String(k).split('|').at(-1)||''}
